mapper.select:
SELECT date, orderCount, totalAmount, averageAmount FROM ( SELECT DATE_FORMAT(DATE(create_time), '%Y-%m-%d') AS date, COUNT(*) AS orderCount, COALESCE(SUM(total_amount), 0) AS totalAmount, CASE WHEN COUNT(*) > 0 THEN COALESCE(SUM(total_amount) / COUNT(*), 0) ELSE 0 END AS averageAmount FROM sys_order WHERE status > 0
AND DATE(create_time) >= #{startDate}
AND DATE(create_time) <= #{endDate}
GROUP BY DATE_FORMAT(DATE(create_time), '%Y-%m-%d') ) t ORDER BY date DESC
